print(f"  Using {len(curves)} curves")

print(f"  {'p':>3s}  {'beta_emp':>12s}  {'_sage_const_1 /(p+_sage_const_1 )':>12s}  {'ratio':>10s}  {'n':>5s}")

for p in [_sage_const_2 , _sage_const_3 , _sage_const_5 , _sage_const_7 , _sage_const_11 , _sage_const_13 , _sage_const_17 , _sage_const_23 , _sage_const_37 , _sage_const_53 , _sage_const_97 ]:
    ap_vals = []
    lf_vals = []

    for E in curves:
        N = int(E.conductor())
        if N % p == _sage_const_0 :
            continue
        ap = int(E.ap(p))
        denom = _sage_const_1  - float(ap)/p + _sage_const_1p0 /p
        if abs(denom) > _sage_const_1en15 :
            ap_vals.append(float(ap))
            lf_vals.append(-math.log(abs(denom)))

    if len(ap_vals) < _sage_const_10 :
        continue

    n_pts = len(ap_vals)
    mean_ap = sum(ap_vals) / n_pts
    mean_lf = sum(lf_vals) / n_pts
    cov = sum((ap_vals[i]-mean_ap)*(lf_vals[i]-mean_lf) for i in range(n_pts)) / n_pts
    var_ap = sum((ap_vals[i]-mean_ap)**_sage_const_2  for i in range(n_pts)) / n_pts
    beta_emp = cov / var_ap if var_ap > _sage_const_0  else _sage_const_0 
    theory = _sage_const_1p0  / (p + _sage_const_1 )
    ratio = beta_emp / theory

    print(f"  {p:>3d}  {beta_emp:>12.8f}  {theory:>12.8f}  {ratio:>10.6f}  {n_pts:>5d}")


